const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const secret = body.internal_secret || '';
const expected = process.env.INTERNAL_EMAIL_SECRET || '';
if (!expected || secret !== expected) return { json: { _unauthorized: true, error: 'internal secret required' } };
if (!body.policy_recommendation_id) return { json: { _empty: true, error: 'policy_recommendation_id required' } };
return { json: { _authorized: true, policy_recommendation_id: body.policy_recommendation_id } };

const rows = $input.item.json;
const rec = (Array.isArray(rows) ? rows[0] : rows) || null;
if (!rec || !rec.id) return { json: { _not_found: true } };
return { json: { recommendation: rec } };

const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    return items;
  } catch (e) { return []; }
};
const suitRows = allOf('Fetch Suitability');
const suit = suitRows[0] || null;
const rec = $('Carry Recommendation').item.json.recommendation;
if (!suit) return { json: { _no_suitability: true } };
return { json: {
  recommendation: rec,
  suitability: suit,
  client_id: suit.client_id,
  advisor_id: suit.advisor_id
} };

const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    return items;
  } catch (e) { return []; }
};
const kycRows = allOf('Fetch Verified KYC');
const discRows = allOf('Fetch Disclosures');
const kyc = kycRows[0] || null;
const disclosures = discRows || [];
const carry = $('Carry Suit + Rec').item.json;
const suit = carry.suitability;
const rec = carry.recommendation;

const systemPrompt = [
  'You are the Crystallux AI Application Builder for the INSURANCE vertical (vertical_id=insurance).',
  'Auto-complete a carrier policy application from aggregated client data.',
  '',
  'Output strictly JSON. Schema:',
  '{',
  '  "application_data": { ... },                       // completed fields',
  '  "fields_requiring_human_input": [ { "field": "<name>", "reason": "<why advisor must input" } ],',
  '  "reasoning": "<2-4 sentences"',
  '}',
  '',
  'For ' + rec.product_type + ' / ' + rec.carrier_name + ':',
  '- applicant_legal_name (from kyc identity_data)',
  '- date_of_birth (from kyc)',
  '- address (from kyc)',
  '- coverage_amount_cents (from recommendation)',
  '- term_years (from recommendation)',
  '- premium_monthly_cents (from recommendation)',
  '- beneficiaries — REQUIRES HUMAN INPUT (advisor must capture)',
  '- medical_questionnaire — REQUIRES HUMAN INPUT (advisor must walk client through)',
  '- existing_coverage — from suitability.client_situation if captured',
  '- payment_method — REQUIRES HUMAN INPUT',
  '',
  'Rules:',
  '- Mark a field requires_human_input if the answer is missing OR sensitive (medical, financial details).',
  '- Never fabricate data. Empty/unknown stays in fields_requiring_human_input.',
  '- For non-life products (auto/home/commercial), adapt fields appropriately (vehicle VIN, property address, business revenue, etc.).'
].join('\n');

const userPayload = JSON.stringify({
  vertical_id: 'insurance',
  carrier_name: rec.carrier_name,
  product_name: rec.product_name,
  product_type: rec.product_type,
  recommendation: { coverage_amount_cents: rec.coverage_amount, premium_monthly_cents: rec.premium_monthly, premium_annual_cents: rec.premium_annual, term_years: rec.term_years },
  kyc_identity_data: kyc && kyc.identity_data ? { has: true, name: kyc.identity_data.first_name + ' ' + kyc.identity_data.last_name, dob: kyc.identity_data.dob, has_address: !!kyc.identity_data.address } : { has: false },
  suitability_situation_keys: Object.keys(suit.client_situation || {}),
  disclosures_signed: (disclosures || []).filter(function (d) { return !!d.acknowledged_at; }).map(function (d) { return d.disclosure_type; })
});

return { json: {
  carry: { recommendation: rec, suitability: suit, kyc: kyc, disclosures: disclosures, client_id: carry.client_id, advisor_id: carry.advisor_id },
  claude_payload: {
    model: 'claude-sonnet-4-5-20250929',
    max_tokens: 1500,
    temperature: 0.1,
    system: systemPrompt,
    messages: [ { role: 'user', content: userPayload } ]
  }
} };

const carry = $('Build Claude Prompt').item.json.carry;
const resp = $input.item.json || {};
let text = '';
try { text = (resp.content && resp.content[0] && resp.content[0].text) || ''; } catch (e) {}
let parsed = null;
try { parsed = JSON.parse(String(text).replace(/```json|```/g, '').trim()); } catch (e) {}
if (!parsed) parsed = { application_data: {}, fields_requiring_human_input: [{ field: 'all_fields', reason: 'AI build failed; advisor to complete manually.' }], reasoning: 'parse_failed' };

const rec = carry.recommendation;
const suit = carry.suitability;
const tokens = (resp.usage && (resp.usage.input_tokens + resp.usage.output_tokens)) || 0;

return { json: {
  insert_row: {
    vertical_id: 'insurance',
    client_id: carry.client_id,
    advisor_id: carry.advisor_id,
    suitability_assessment_id: suit.id,
    policy_recommendation_id: rec.id,
    carrier_name: rec.carrier_name,
    application_data: parsed.application_data || {},
    fields_requiring_human_input: parsed.fields_requiring_human_input || [],
    advisor_review_status: 'pending',
    submission_status: 'draft',
    locked: false
  },
  client_id: carry.client_id,
  advisor_id: carry.advisor_id,
  tokens: tokens
} };
